use strict;
use warnings;

my $text = "Merhaba, benim adim Ahmet ve 25 yasindayim.";

# Eslesme kontrolu
if ($text =~ /Ahmet/) {
    print "'Ahmet' metinde bulundu.\n";
}

# Sayi cikarma
if ($text =~ /(\d+)/) {
    print "Bulunan sayi: $1\n";
}

# Degistirme (substitution)
my $replaced = $text;
$replaced =~ s/Ahmet/Mehmet/;
print "\nDegistirilmis: $replaced\n";

# Global degistirme
my $sentence = "kedi kopek kedi kus kedi";
(my $count = $sentence) =~ s/kedi/hayvan/g;
print "\nGlobal degisim: $count\n";

# Bolme (split)
my $csv = "elma,armut,muz,karpuz";
my @fruits = split /,/, $csv;
print "\nMeyveler:\n";
print "- $_\n" for @fruits;

# E-posta formati kontrolu
my @emails = ("test\@example.com", "gecersiz-eposta", "user\@domain.org");
print "\nE-posta kontrolleri:\n";
foreach my $email (@emails) {
    if ($email =~ /^[\w.]+\@[\w.]+\.\w+$/) {
        print "$email -> Gecerli\n";
    } else {
        print "$email -> Gecersiz\n";
    }
}
